"use strict";const VERSION="technominds-v58",STATIC_CACHE=`${VERSION}-static`,PAGE_CACHE=`${VERSION}-pages`,APP_SHELL=["./","./index.html","./offline.html","./assets/site.css?v=58","./assets/future-theme.css?v=58","./assets/app.js?v=58","./assets/technominds-logo.png?v=58","./site.webmanifest?v=58"];self.addEventListener("install",t=>{t.waitUntil(caches.open(STATIC_CACHE).then(e=>e.addAll(APP_SHELL)).then(()=>self.skipWaiting()))}),self.addEventListener("activate",t=>{t.waitUntil(caches.keys().then(e=>Promise.all(e.filter(s=>![STATIC_CACHE,PAGE_CACHE].includes(s)).map(s=>caches.delete(s)))).then(()=>self.clients.claim()))});function isApplicationApi(t){return t.hostname.includes("cloudfunctions.net")||t.hostname.includes("firestore.googleapis.com")||t.hostname.includes("googleapis.com")||t.pathname.includes("/__/auth/")}self.addEventListener("fetch",t=>{const e=t.request;if(e.method!=="GET")return;const s=new URL(e.url);if(!isApplicationApi(s)){if(e.mode==="navigate"){t.respondWith(fetch(e).then(n=>(n.ok&&caches.open(PAGE_CACHE).then(i=>i.put(e,n.clone())),n)).catch(async()=>await caches.match(e)||caches.match("./offline.html")));return}s.origin===self.location.origin&&t.respondWith(caches.match(e).then(n=>n||fetch(e).then(i=>(i.ok&&caches.open(STATIC_CACHE).then(c=>c.put(e,i.clone())),i))))}});
